return {
          draw: function(ctx, W, H, t, dt) {
            ctx.fillStyle = '#F5F0E8';
            ctx.fillRect(0, 0, W, H);

            // Title
            ctx.fillStyle = '#333';
            ctx.font = 'bold 14px Arial';
            ctx.fillText('Classical Scale (Everyday)', 20, 30);
            ctx.fillText('Quantum Scale (Atomic)', W/2 + 20, 30);

            // Classical side - smooth trajectory
            ctx.strokeStyle = '#DC2626';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(50, 100);
            for(let i = 0; i <= 100; i += 5) {
              ctx.lineTo(50 + i, 100 + Math.sin(i/20)*30);
            }
            ctx.stroke();

            // Ball on classical side
            ctx.fillStyle = '#DC2626';
            ctx.beginPath();
            ctx.arc(50 + (t%100), 100 + Math.sin((t%100)/20)*30, 8, 0, Math.PI*2);
            ctx.fill();

            ctx.fillStyle = '#666';
            ctx.font = '12px Arial';
            ctx.fillText('Smooth path', 50, 160);
            ctx.fillText('Predictable', 50, 175);

            // Quantum side - fuzzy/probability
            ctx.fillStyle = 'rgba(59, 130, 246, 0.3)';
            for(let i = 0; i < 20; i++) {
              const x = W/2 + 50 + Math.random()*80;
              const y = 100 + Math.random()*80;
              ctx.beginPath();
              ctx.arc(x, y, Math.random()*6, 0, Math.PI*2);
              ctx.fill();
            }

            ctx.fillStyle = '#3B82F6';
            ctx.beginPath();
            ctx.arc(W/2 + 90, 130, 10, 0, Math.PI*2);
            ctx.fill();

            ctx.fillStyle = '#666';
            ctx.fillText('Probability cloud', W/2 + 50, 220);
            ctx.fillText('Uncertain', W/2 + 50, 235);
          }
        };
